defaultpen(linewidth(.7pt)+fontsize(8pt));
pair A=(0,0), B=(7,0), C=(8,-4), D=(-2,-4), Ep=3/7*D+4/7*A, F=3/7*C+4/7*B, G=(14/3,28/3);
pair[] dots={A, B, C, D, Ep, F, G};
draw(dots);

draw(G--C--D--cycle);
draw(A--B);
draw(Ep--F);
label("$A$",A,NW);
label("$B$",B,NE);
label("$C$",C,SE);
label("$D$",D,SW);
label("$E$",Ep,W);
label("$F$",F,E);
label("$G$",G,N);
label("$x$",midpoint(G--B),W);
label("$3y$",midpoint(B--F),W);
label("$4y$",midpoint(F--C),W);
label("$7$",midpoint(A--B),N);
label("$10$",midpoint(C--D),N); [/asy]

The greatest common factor of $45x$ and 30 is 15. We factor 15 out of both terms to get\begin{align*}
45x+30 &= 15\cdot 3x + 15 \cdot 2\\
&= \boxed{15(3x+2)}.
\end{align*}

